import{_ as e,o as i,c as a,a5 as n}from"./chunks/framework.COADHF96.js";const g=JSON.parse('{"title":"Authentication","description":"Authenticate the Picsart gen-ai CLI and MCP with OAuth web login (gen-ai login) — no API keys.","frontmatter":{"description":"Authenticate the Picsart gen-ai CLI and MCP with OAuth web login (gen-ai login) — no API keys.","head":[["link",{"rel":"canonical","href":"https://picsart.github.io/picsart-mcp-cli-docs/guide/authentication"}],["meta",{"property":"og:title","content":"Authentication"}],["meta",{"property":"og:description","content":"Authenticate the Picsart gen-ai CLI and MCP with OAuth web login (gen-ai login) — no API keys."}],["meta",{"property":"og:url","content":"https://picsart.github.io/picsart-mcp-cli-docs/guide/authentication"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Authentication"}],["meta",{"name":"twitter:description","content":"Authenticate the Picsart gen-ai CLI and MCP with OAuth web login (gen-ai login) — no API keys."}]]},"headers":[],"relativePath":"guide/authentication.md","filePath":"guide/authentication.md","lastUpdated":1781793404000}'),s={name:"guide/authentication.md"};function o(d,t,r,c,h,l){return i(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h1><p>All interfaces use your Picsart account via <strong>OAuth web login</strong> — there are no API keys to create or paste. Generation spends credits, so it always requires sign-in; browsing the catalog and inspecting models does not.</p><h2 id="sign-in" tabindex="-1">Sign in <a class="header-anchor" href="#sign-in" aria-label="Permalink to &quot;Sign in&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gen-ai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # OAuth web login — opens your browser to confirm your identity</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gen-ai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whoami</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # shows the current user</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gen-ai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> credits</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # remaining credits on your account</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gen-ai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> logout</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # clears credentials</span></span></code></pre></div><p><code>gen-ai login</code> runs the OAuth web flow: the CLI opens your browser, you authorize once, and a secure token is stored locally — no password is saved and no credentials are exposed. Credentials are kept at <code>~/.gen-ai/credentials.json</code> (permissions <code>600</code>), and the CLI auto-refreshes the access token on a <code>401</code>; if refresh fails, run <code>gen-ai login</code> again.</p><p>This single sign-in covers all three surfaces — the CLI, <a href="/picsart-mcp-cli-docs/guide/skills">Skills</a>, and <a href="/picsart-mcp-cli-docs/guide/mcp-quickstart">MCP</a> — because Skills and MCP drive the same CLI engine.</p><h2 id="agents-skills-mcp" tabindex="-1">Agents (Skills &amp; MCP) <a class="header-anchor" href="#agents-skills-mcp" aria-label="Permalink to &quot;Agents (Skills &amp; MCP)&quot;">​</a></h2><p>Agents authenticate through the same OAuth web login. After installing the CLI, run <code>gen-ai login</code> once on the machine; the agent (Claude Code, Cursor, Windsurf, ChatGPT, Codex) then generates using that authorized session. There are no separate keys to configure in the agent — see <a href="/picsart-mcp-cli-docs/guide/installation">Installation</a> and the <a href="/picsart-mcp-cli-docs/guide/mcp-quickstart">MCP Quickstart</a>.</p><h2 id="what-needs-sign-in" tabindex="-1">What needs sign-in? <a class="header-anchor" href="#what-needs-sign-in" aria-label="Permalink to &quot;What needs sign-in?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Action</th><th>CLI</th><th>MCP tool</th><th>Sign-in</th></tr></thead><tbody><tr><td>Browse catalog</td><td><code>gen-ai models</code></td><td><code>picsart_list_models</code></td><td>❌ no</td></tr><tr><td>Inspect a model</td><td><code>gen-ai models info &lt;id&gt;</code></td><td><code>picsart_model_info</code></td><td>❌ no</td></tr><tr><td>Quote a cost</td><td><code>gen-ai pricing &lt;id&gt;</code></td><td><code>picsart_pricing</code></td><td>✅ yes</td></tr><tr><td>Generate</td><td><code>gen-ai generate</code></td><td><code>picsart_generate</code></td><td>✅ yes</td></tr><tr><td>Drive upload/list</td><td><code>gen-ai upload</code> / <code>list</code></td><td><code>picsart_drive_*</code></td><td>✅ yes</td></tr></tbody></table>`,10)])])}const u=e(s,[["render",o]]);export{g as __pageData,u as default};
